import org.apache.spark.sql.{SparkSession, DataFrame}
import org.apache.spark.sql.functions._
import java.util.UUID
import scala.util.{Try, Success, Failure}

case class QueryRequest(sql: String)
case class QueryResponse(success: Boolean, result: Option[String], error: Option[String])

object AnalyticsPlatform {
  private val spark: SparkSession = SparkSession.builder()
    .appName("AnalyticsPlatform")
    .config("spark.sql.adaptive.enabled", "true")
    .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
    .getOrCreate()

  def executeQuery(sql: String): QueryResponse = {
    try {
      val queryId = UUID.randomUUID().toString
      val startTime = System.currentTimeMillis()
      
      val result = spark.sql(sql)
      
      val endTime = System.currentTimeMillis()
      val executionTime = endTime - startTime
      
      val resultJson = if (result.columns.nonEmpty) {
        val sampleData = result.limit(1000).collect()
        val jsonRows = sampleData.map(row => {
          val fields = row.getValuesMap(row.schema.fieldNames)
          fields.map { case (k, v) => k -> v.toString }.mkString("{", ",", "}")
        }).mkString("[", ",", "]")
        Some(jsonRows)
      } else {
        Some("[]")
      }
      
      QueryResponse(success = true, result = resultJson, error = None)
    } catch {
      case e: Exception =>
        QueryResponse(success = false, result = None, error = Some(e.getMessage))
    }
  }
  
  def processQuery(request: QueryRequest): QueryResponse = {
    if (request.sql.trim.isEmpty) {
      QueryResponse(success = false, result = None, error = Some("SQL query cannot be empty"))
    } else {
      executeQuery(request.sql)
    }
  }
  
  def close(): Unit = {
    spark.stop()
  }
}

